// Provide a deterministic analyzed content item for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    content: 'AI Agent 不應只負責生成文字，也應根據工具結果規劃下一步。',
    images: [],
    tags: ['AI', 'n8n'],
    score: 85,
    shouldWrite: true,
    analysis: {
      topic: 'AI Agent',
      coreIdea: 'AI Agent 應根據工具結果規劃下一步',
      audience: 'n8n 與自動化使用者',
      angles: ['Agent orchestration', 'Tool use'],
      keywords: ['AI Agent', 'workflow automation'],
      researchQuestions: ['什麼是 AI Agent？', 'AI Agent 如何使用工具？'],
      riskNotes: []
    },
    metadata: {
      createdAt: new Date().toISOString(),
      collector: 'manual-test',
      version: '1.0.0',
      status: 'analyzed'
    }
  }
}];

// Build a concise Wikipedia search query from the analyzed content.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.analysis?.topic) {
  throw new Error('analysis.topic is required');
}

const terms = [
  body.analysis.topic,
  ...(Array.isArray(body.analysis.keywords) ? body.analysis.keywords.slice(0, 2) : [])
].filter(Boolean);

const query = [...new Set(terms)].join(' ');

return [{
  json: {
    original: body,
    query,
    language: body.language || 'zh-TW'
  }
}];

// Convert Wikipedia API output into compact research sources.
const response = $input.first().json;
const original = $('BuildResearchQuery').first().json.original;
const query = $('BuildResearchQuery').first().json.query;
const pages = Object.values(response.query?.pages ?? {});

const sources = pages
  .map((page) => ({
    title: String(page.title ?? ''),
    url: String(page.fullurl ?? ''),
    excerpt: String(page.extract ?? '').trim()
  }))
  .filter((source) => source.title && source.url && source.excerpt)
  .slice(0, 5);

return [{
  json: {
    original,
    research: {
      query,
      sources,
      sourceCount: sources.length
    }
  }
}];

// Merge the research context into the content item.
const input = $input.first().json;
const original = input.original;
const research = input.research;

return [{
  json: {
    ...original,
    research: {
      query: research.query,
      sources: research.sources,
      sourceCount: research.sourceCount,
      notes: research.sourceCount
        ? 'Wikipedia context collected. Verify time-sensitive claims against official sources later.'
        : 'No Wikipedia result found.'
    },
    metadata: {
      ...original.metadata,
      researcher: '04-research-agent',
      researcherVersion: '0.4.0',
      status: 'researched',
      researchedAt: new Date().toISOString()
    }
  }
}];
